## 3. Build script – `CMakeLists.txt`

```cmake
# ---------------------------------------------------------------
# file: CMakeLists.txt
# ---------------------------------------------------------------
cmake_minimum_required(VERSION 3.15)
project(libpcapng_python_bindings LANGUAGES CXX)

# ---- Find pybind11 -------------------------------------------------
# You can either install pybind11 system‑wide or use the FetchContent
# approach shown here.
include(FetchContent)

FetchContent_Declare(
    pybind11
    GIT_REPOSITORY https://github.com/pybind/pybind11.git
    GIT_TAG        v2.11.1   # or any recent tag
)
FetchContent_MakeAvailable(pybind11)

# ---- Build the module ------------------------------------------------
add_library(libpcapng MODULE libpcapng_binding.cpp)

# C++17 is enough for the stub; adapt to your real library's requirements.
target_compile_features(libpcapng PRIVATE cxx_std_17)

# Link against pybind11
target_link_libraries(libpcapng PRIVATE pybind11::module)

# Platform‑specific suffix for a Python extension module
set_target_properties(libpcapng PROPERTIES
    PREFIX ""          # no "lib" prefix on *nix
    SUFFIX ".so"       # Windows will automatically use .pyd
)

# ---- Optional: if you have the real libpcapng library ----------------
# find_library(PCAPNG_LIB pcapng)   # <-- adjust name/path
# target_link_libraries(libpcapng PRIVATE ${PCAPNG_LIB})

# ---------------------------------------------------------------
# After a successful build you will get a file:
#   build/libpcapng.cpython-311-x86_64-linux-gnu.so
# (or .pyd on Windows).  Put that file on your PYTHONPATH or install it
# with pip (see below).
```

### Quick build instructions

```bash
# 1️⃣  Create a build directory
mkdir build && cd build

# 2️⃣  Configure + build (assumes you have a recent CMake & a C++ compiler)
cmake .. -DPYTHON_EXECUTABLE=$(which python3)
cmake --build . -j$(nproc)

# 3️⃣  Test the import
python3 -c "import libpcapng, inspect; print(inspect.getdoc(libpcapng.PcapngReader))"
```

If you want to **install the module** into a virtualenv:

```bash
