## 4. (Optional) `setup.py` wrapper for pip‑installable wheels

If you prefer a classic `pip install .` workflow, add a tiny `setup.py`:

```python
# ---------------------------------------------------------------
# file: setup.py
# ---------------------------------------------------------------
import pathlib, sys, subprocess, os
from setuptools import setup, Extension
from setuptools.command.build_ext import build_ext

# Helper to invoke CMake
class CMakeBuild(build_ext):
    def run(self):
        for ext in self.extensions:
            self.build_cmake(ext)

    def build_cmake(self, ext):
        extdir = pathlib.Path(self.get_ext_fullpath(ext.name)).parent.absolute()
        cfg = "Debug" if self.debug else "Release"
        cmake_args = [
            f"-DCMAKE_LIBRARY_OUTPUT_DIRECTORY={extdir}",
            f"-DPYTHON_EXECUTABLE={sys.executable}",
            f"-DCMAKE_BUILD_TYPE={cfg}",
        ]

        build_temp = pathlib.Path(self.build_temp) / ext.name
        build_temp.mkdir(parents=True, exist_ok=True)

        subprocess.check_call(["cmake", str(ext.sourcedir)] + cmake_args,
                              cwd=build_temp)
        subprocess.check_call(["cmake", "--build", ".", "--config", cfg],
                              cwd=build_temp)

class CMakeExtension(Extension):
    def __init__(self, name, sourcedir=""):
        super().__init__(name, sources=[])
        self.sourcedir = pathlib.Path(sourcedir).absolute()

setup(
    name="libpcapng",
    version="0.1.0",
    author="Your Name",
    description="Python bindings for libpcapng",
    long_description="See README for details.",
    ext_modules=[CMakeExtension("libpcapng")],
    cmdclass={"build_ext": CMakeBuild},
    zip_safe=False,
)
```

Now `pip install .` will invoke CMake automatically and produce a wheel that works on the target platform.

